     }
+
+    #[test]
+    fn quoted_path_does_not_bypass_rm() {
+        let pack = create_pack();
+        assert_blocks_with_pattern(
+            &pack,
+            "rm -f \"/etc/nginx/nginx.conf\"",
+            "nginx-config-delete",
+        );
+        assert_blocks_with_pattern(
+            &pack,
+            "rm -rf '/etc/nginx/sites-available/'",
+            "nginx-config-delete",
+        );
+    }
